package tests;import base.BaseTest;import pages.CocineroPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;import org.openqa.selenium.By;import org.openqa.selenium.WebElement;import org.openqa.selenium.support.ui.Select;import org.openqa.selenium.support.ui.WebDriverWait;import java.time.Duration;import java.util.List;public class HP04MarcarPedidoEntregadoTest extends BaseTest {    @Test    void cocineroMarcaPedidoComoEntregado() {        try {            System.out.println("Ejecutando HP-04: Marcar pedido como entregado");            WebDriverWait wait = new WebDriverWait(driver, Duration.ofSeconds(15));            LoginPage loginPage = new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion("camarero", "123");            wait.until(d -> d.findElement(                    By.xpath("//a[contains(text(),'Crear pedido') or contains(text(),'Crear Pedido')]")            )).click();            List<WebElement> selects = wait.until(d -> d.findElements(By.tagName("select")));            Assertions.assertFalse(selects.isEmpty(), "No se encontró el selector de productos.");            Select productos = new Select(selects.get(0));            productos.selectByVisibleText(productos.getOptions().get(1).getText());            WebElement cantidad = wait.until(d ->                    d.findElement(By.cssSelector("input[type='number']"))            );            cantidad.clear();            cantidad.sendKeys("1");            wait.until(d -> d.findElement(                    By.xpath("//button[contains(text(),'Agregar')]")            )).click();            wait.until(d -> d.findElement(                    By.xpath("//button[contains(text(),'Guardar Pedido')]")            )).click();            wait.until(d -> {                String texto = d.getPageSource();                return texto.contains("Pedidos Actuales") || texto.contains("Pendiente");            });            driver.manage().deleteAllCookies();            loginPage.abrirLogin();            loginPage.iniciarSesion("cocinero", "123");            CocineroPage cocineroPage = new CocineroPage(driver);            boolean existePendiente = wait.until(d ->                    cocineroPage.cantidadBotonesComenzarPreparacion() > 0            );            Assertions.assertTrue(                    existePendiente,                    "No existe ningún pedido pendiente para preparar el caso HP-04."            );            int pendientesAntes = cocineroPage.cantidadBotonesComenzarPreparacion();            cocineroPage.comenzarPreparacion();            boolean pasoAEnPreparacion = wait.until(d ->                    cocineroPage.cantidadBotonesMarcarComoEntregado() > 0            );            Assertions.assertTrue(                    pasoAEnPreparacion,                    "El pedido no pasó correctamente a En Preparación."            );            int enPreparacionAntes = cocineroPage.cantidadBotonesMarcarComoEntregado();            cocineroPage.marcarComoEntregado();            boolean pedidoEntregado = wait.until(d ->                    cocineroPage.cantidadBotonesMarcarComoEntregado() < enPreparacionAntes            );            Assertions.assertTrue(                    pedidoEntregado,                    "El pedido no fue marcado como entregado correctamente."            );            System.out.println("HP-04 ejecutado correctamente.");        } catch (Exception e) {            Assertions.fail("Error en HP-04: " + e.getMessage());        }    }}